import{_ as e,o as s,c as n,a2 as i}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Diseno y desarrollo de flujos en NiFi","description":"","frontmatter":{},"headers":[],"relativePath":"data-engineering/nifi/02-diseno-y-desarrollo-de-flujos.md","filePath":"data-engineering/nifi/02-diseno-y-desarrollo-de-flujos.md","lastUpdated":1782521464000}'),o={name:"data-engineering/nifi/02-diseno-y-desarrollo-de-flujos.md"};function t(l,a,r,p,d,c){return s(),n("div",null,[...a[0]||(a[0]=[i(`<h1 id="diseno-y-desarrollo-de-flujos-en-nifi" tabindex="-1">Diseno y desarrollo de flujos en NiFi <a class="header-anchor" href="#diseno-y-desarrollo-de-flujos-en-nifi" aria-label="Permalink to &quot;Diseno y desarrollo de flujos en NiFi&quot;">​</a></h1><p>Disenar en NiFi no consiste en arrastrar procesadores hasta que algo funcione. Un flujo mantenible debe expresar responsabilidades, controlar errores y permitir operar sin miedo.</p><h2 id="modelo-mental" tabindex="-1">Modelo mental <a class="header-anchor" href="#modelo-mental" aria-label="Permalink to &quot;Modelo mental&quot;">​</a></h2><p>Piensa cada flujo como una serie de etapas:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>entrada -&gt; normalizacion -&gt; validacion -&gt; routing -&gt; salida -&gt; errores</span></span></code></pre></div><p>Cada etapa deberia poder explicarse con una frase. Si un process group necesita una pagina entera para entenderse, probablemente esta mezclando demasiadas responsabilidades.</p><h2 id="nombres-y-estructura" tabindex="-1">Nombres y estructura <a class="header-anchor" href="#nombres-y-estructura" aria-label="Permalink to &quot;Nombres y estructura&quot;">​</a></h2><p>Usa nombres orientados a negocio:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Ingesta de pedidos desde SFTP</span></span>
<span class="line"><span>Validacion de esquema de pedidos</span></span>
<span class="line"><span>Publicacion en Kafka ventas.pedidos</span></span>
<span class="line"><span>Errores de pedidos invalidos</span></span></code></pre></div><p>Evita nombres genericos:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GetFile 1</span></span>
<span class="line"><span>ProcessGroup final</span></span>
<span class="line"><span>Test nuevo</span></span>
<span class="line"><span>Processor copia</span></span></code></pre></div><h2 id="process-groups-recomendados" tabindex="-1">Process groups recomendados <a class="header-anchor" href="#process-groups-recomendados" aria-label="Permalink to &quot;Process groups recomendados&quot;">​</a></h2><p>Una estructura habitual:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01 Entrada</span></span>
<span class="line"><span>02 Validacion</span></span>
<span class="line"><span>03 Enriquecimiento</span></span>
<span class="line"><span>04 Publicacion</span></span>
<span class="line"><span>90 Reintentos</span></span>
<span class="line"><span>99 Errores</span></span></code></pre></div><p>No hace falta seguir exactamente esa numeracion, pero ayuda a que el canvas tenga lectura de izquierda a derecha.</p><h2 id="relationships" tabindex="-1">Relationships <a class="header-anchor" href="#relationships" aria-label="Permalink to &quot;Relationships&quot;">​</a></h2><p>Cada processor tiene salidas posibles llamadas relationships. Algunas comunes:</p><ul><li><code>success</code></li><li><code>failure</code></li><li><code>retry</code></li><li><code>original</code></li><li><code>matched</code></li><li><code>unmatched</code></li></ul><p>Una relationship sin conectar puede bloquear el processor, salvo que se marque como auto-terminated. Auto-terminar una relacion significa descartar esos FlowFiles, asi que debe ser una decision explicita.</p><h2 id="routing-por-atributos" tabindex="-1">Routing por atributos <a class="header-anchor" href="#routing-por-atributos" aria-label="Permalink to &quot;Routing por atributos&quot;">​</a></h2><p><code>RouteOnAttribute</code> permite enviar FlowFiles a rutas distintas segun sus atributos.</p><p>Ejemplo:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>\${mime.type:equals(&#39;application/json&#39;)}</span></span>
<span class="line"><span>\${filename:endsWith(&#39;.csv&#39;)}</span></span>
<span class="line"><span>\${source:equals(&#39;crm&#39;)}</span></span></code></pre></div><p>Uso tipico:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>entrada -&gt; RouteOnAttribute</span></span>
<span class="line"><span>  -&gt; json -&gt; flujo JSON</span></span>
<span class="line"><span>  -&gt; csv -&gt; flujo CSV</span></span>
<span class="line"><span>  -&gt; unmatched -&gt; errores</span></span></code></pre></div><h2 id="routing-por-contenido" tabindex="-1">Routing por contenido <a class="header-anchor" href="#routing-por-contenido" aria-label="Permalink to &quot;Routing por contenido&quot;">​</a></h2><p>Cuando la decision depende del contenido, puedes usar processors como:</p><ul><li><code>EvaluateJsonPath</code></li><li><code>EvaluateXPath</code></li><li><code>ExtractText</code></li><li><code>QueryRecord</code></li><li><code>ValidateRecord</code></li></ul><p>Patron comun:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>EvaluateJsonPath -&gt; RouteOnAttribute -&gt; salida especifica</span></span></code></pre></div><p>Extrae lo minimo necesario a atributos. No conviertas cada campo de negocio en atributo si el contenido es grande.</p><h2 id="formato-record" tabindex="-1">Formato Record <a class="header-anchor" href="#formato-record" aria-label="Permalink to &quot;Formato Record&quot;">​</a></h2><p>La familia de processors <code>Record</code> permite trabajar con CSV, JSON, Avro, Parquet y otros formatos de manera mas estructurada.</p><p>Ejemplos:</p><ul><li><code>ConvertRecord</code></li><li><code>ValidateRecord</code></li><li><code>QueryRecord</code></li><li><code>PutDatabaseRecord</code></li><li><code>PublishKafkaRecord_2_6</code></li></ul><p>Necesitan lectores y escritores configurados como controller services.</p><h2 id="ejemplo-ingesta-de-csv" tabindex="-1">Ejemplo: ingesta de CSV <a class="header-anchor" href="#ejemplo-ingesta-de-csv" aria-label="Permalink to &quot;Ejemplo: ingesta de CSV&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GetFile</span></span>
<span class="line"><span>  -&gt; UpdateAttribute</span></span>
<span class="line"><span>  -&gt; ValidateRecord</span></span>
<span class="line"><span>      -&gt; valid -&gt; ConvertRecord -&gt; PutDatabaseRecord</span></span>
<span class="line"><span>      -&gt; invalid -&gt; PutFile cuarentena</span></span></code></pre></div><p>Controles recomendados:</p><ul><li>Guardar ruta y nombre original.</li><li>Anadir identificador de ejecucion.</li><li>Validar esquema.</li><li>Separar registros invalidos.</li><li>Publicar metricas de volumen.</li></ul><h2 id="ejemplo-api-a-kafka" tabindex="-1">Ejemplo: API a Kafka <a class="header-anchor" href="#ejemplo-api-a-kafka" aria-label="Permalink to &quot;Ejemplo: API a Kafka&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GenerateTableFetch</span></span>
<span class="line"><span>  -&gt; ExecuteSQLRecord</span></span>
<span class="line"><span>  -&gt; ConvertRecord</span></span>
<span class="line"><span>  -&gt; PublishKafkaRecord_2_6</span></span></code></pre></div><p>O para HTTP:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>InvokeHTTP</span></span>
<span class="line"><span>  -&gt; EvaluateJsonPath</span></span>
<span class="line"><span>  -&gt; RouteOnAttribute</span></span>
<span class="line"><span>  -&gt; PublishKafkaRecord_2_6</span></span></code></pre></div><h2 id="documentacion-del-flujo" tabindex="-1">Documentacion del flujo <a class="header-anchor" href="#documentacion-del-flujo" aria-label="Permalink to &quot;Documentacion del flujo&quot;">​</a></h2><p>Cada process group importante deberia documentar:</p><ul><li>Objetivo.</li><li>Fuente.</li><li>Destino.</li><li>Frecuencia.</li><li>Formato esperado.</li><li>Relaciones de error.</li><li>Parametros necesarios.</li><li>Propietario.</li></ul><p>NiFi permite anadir comentarios y labels en el canvas. Usalos para decisiones que no sean obvias.</p><h2 id="checklist-de-desarrollo" tabindex="-1">Checklist de desarrollo <a class="header-anchor" href="#checklist-de-desarrollo" aria-label="Permalink to &quot;Checklist de desarrollo&quot;">​</a></h2><ul><li>El flujo tiene grupos por responsabilidad.</li><li>Los nombres explican intencion.</li><li>Todas las relationships estan conectadas o terminadas de forma consciente.</li><li>Hay rutas separadas para exito, retry y fallo definitivo.</li><li>Las rutas, hosts y credenciales son parametros.</li><li>Los controller services estan reutilizados.</li><li>La salida final es idempotente o deduplicable.</li><li>El flujo queda versionado en Registry.</li></ul><h2 id="recursos-relacionados" tabindex="-1">Recursos relacionados <a class="header-anchor" href="#recursos-relacionados" aria-label="Permalink to &quot;Recursos relacionados&quot;">​</a></h2><ul><li><a href="./04-procesadores-controller-services-y-parametros">Procesadores, controller services y parametros</a></li><li><a href="./05-colas-back-pressure-y-errores">Colas, back pressure y errores</a></li><li><a href="./../pipelines/01-introduccion">Pipelines de datos</a></li></ul>`,52)])])}const g=e(o,[["render",t]]);export{h as __pageData,g as default};
